import asyncio
import websockets
import json
from collections import defaultdict

class Player:
    def __init__(self, username):
        self.username = username
        self.inventory = defaultdict(int)

class GameServer:
    def __init__(self):
        self.players = {}
        self.lock = asyncio.Lock()

    async def register(self, websocket, username):
        async with self.lock:
            self.players[username] = Player(username)
            await self.send_inventory(websocket, username)

    async def unregister(self, username):
        async with self.lock:
            del self.players[username]

    async def send_inventory(self, websocket, username):
        inventory = self.players[username].inventory
        await websocket.send(json.dumps({"action": "update_inventory", "inventory": dict(inventory)}))

    async def trade_items(self, sender_username, receiver_username, item, quantity):
        async with self.lock:
            sender = self.players[sender_username]
            receiver = self.players[receiver_username]

            if sender.inventory[item] >= quantity:
                sender.inventory[item] -= quantity
                receiver.inventory[item] += quantity
                return True
            return False

    async def handle_connection(self, websocket, path):
        username = await websocket.recv()
        await self.register(websocket, username)

        try:
            async for message in websocket:
                data = json.loads(message)
                if data['action'] == 'trade':
                    success = await self.trade_items(username, data['receiver'], data['item'], data['quantity'])
                    if success:
                        await self.send_inventory(websocket, username)
                        await self.send_inventory(self.players[data['receiver']], data['receiver'])
        finally:
            await self.unregister(username)

    async def start_server(self):
        async with websockets.serve(self.handle_connection, "localhost", 6789):
            await asyncio.Future()  # run forever

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.start_server())